const listeAlani = document.getElementById('filmListesiAlani');
const kategoriSecimi = document.getElementById('kategoriSecimi'); 

function yorumlariGetir(filmIsmi) {
    const yorumlar = JSON.parse(localStorage.getItem(`yorumlar_${filmIsmi}`)) || [];
    return yorumlar.map(y => `
        <div class="tek-yorum">
            <strong>${y.isim}</strong> <span class="yorum-puani">⭐ ${y.puan}</span>
            <p>${y.metin}</p>
        </div>
    `).join('');
}

window.yorumYap = function(filmIsmi) {

    const idPrefix = filmIsmi.replace(/[^a-zA-Z0-9]/g, ""); 
    const isimInput = document.getElementById(`isim-${idPrefix}`);
    const puanInput = document.getElementById(`puan-${idPrefix}`);
    const metinInput = document.getElementById(`metin-${idPrefix}`);

    if(!isimInput.value || !puanInput.value || !metinInput.value) {
        alert("Lütfen tüm alanları doldurun!");
        return;
    }

    const yeniYorum = {
        isim: isimInput.value,
        puan: puanInput.value,
        metin: metinInput.value
    };

    const mevcutYorumlar = JSON.parse(localStorage.getItem(`yorumlar_${filmIsmi}`)) || [];
    mevcutYorumlar.push(yeniYorum);
    localStorage.setItem(`yorumlar_${filmIsmi}`, JSON.stringify(mevcutYorumlar));

    isimInput.value = "";
    puanInput.value = "";
    metinInput.value = "";

    document.getElementById(`yorum-listesi-${idPrefix}`).innerHTML = yorumlariGetir(filmIsmi);
}

// 1. Sayfa yüklendiğinde tüm filmleri ekrana bas
document.addEventListener("DOMContentLoaded", () => {
    filmleriEkranaBas(Filmler);
});

// 2. Kategori seçimi değiştiğinde filmleri filtrele
kategoriSecimi.addEventListener("change", (e) => {
    const secilenTur = e.target.value.toLowerCase();
    
    if (secilenTur === "tumu") {
        filmleriEkranaBas(Filmler);
    } else {
        // Seçilen türe göre diziyi filtrele (Büyük/küçük harf duyarlılığını ortadan kaldırarak)
        const filtrelenmisFilmler = Filmler.filter(film => film.tur.toLowerCase() === secilenTur);
        filmleriEkranaBas(filtrelenmisFilmler);
    }
});


function filmleriEkranaBas(filmDizisi) {
    listeAlani.innerHTML = "";

    filmDizisi.forEach(film => {
        const kart = document.createElement('div');
        kart.classList.add('film-karti');
        
        const idPrefix = film.isim.replace(/[^a-zA-Z0-9]/g, "");

        const linkButonu = film.izlemeLinki 
            ? `<a href="${film.izlemeLinki}" target="_blank" class="izle-butonu">🎬 Filmi İzle</a>` 
            : '';
        kart.innerHTML = `
            <img src="${film.afis}" alt="${film.isim} afişi">
            <div class="film-detay">
                <h3>${film.isim}</h3>
                <p>${film.konu}</p>
                <div class="alt-bilgi">
                    <span class="puan-etiketi">⭐ ${film.puan}</span>
                    ${linkButonu}
                </div>
                
                <div class="yorum-alani">
                    <h4>Yorumlar</h4>
                    <div class="yorum-listesi" id="yorum-listesi-${idPrefix}">
                        ${yorumlariGetir(film.isim)}
                    </div>
                    
                    <div class="yorum-formu">
                        <div class="yorum-form-ust">
                            <input type="text" id="isim-${idPrefix}" placeholder="Adınız" class="yorum-input">
                            <input type="number" id="puan-${idPrefix}" min="1" max="10" placeholder="Puan" class="yorum-input">
                        </div>
                        <textarea id="metin-${idPrefix}" placeholder="Filmi nasıl buldunuz?" class="yorum-textarea"></textarea>
                        <button onclick="yorumYap('${film.isim}')" class="yorum-gonder-btn">Yorum Yap</button>
                    </div>
                </div>
            </div>
        `;
        listeAlani.appendChild(kart);
    });
}